import { registerToDefault } from '../registry';
import type { SDUIComponentRenderer } from '../models';

import HeadingAdapter from './HeadingAdapter';
import TextAdapter from './TextAdapter';
import BalanceDisplayAdapter from './BalanceDisplayAdapter';
import PointsInputAdapter from './PointsInputAdapter';
import ButtonAdapter from './ButtonAdapter';
import LinkAdapter from './LinkAdapter';
import AlertAdapter from './AlertAdapter';
import ListTextIconAdapter from './ListTextIconAdapter';
import SeparatorAdapter from './SeparatorAdapter';
import IconTextRowAdapter from './IconTextRowAdapter';
import SectionHeadingAdapter from './SectionHeadingAdapter';

const adapters: Record<string, SDUIComponentRenderer> = {
  heading: HeadingAdapter as SDUIComponentRenderer,
  text: TextAdapter as SDUIComponentRenderer,
  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
  points_input: PointsInputAdapter as SDUIComponentRenderer,
  button: ButtonAdapter as SDUIComponentRenderer,
  link: LinkAdapter as SDUIComponentRenderer,
  alert: AlertAdapter as SDUIComponentRenderer,
  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
  separator: SeparatorAdapter as SDUIComponentRenderer,
  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
};

export function registerAllAdapters(): void {
  Object.entries(adapters).forEach(([type, renderer]) => {
    registerToDefault(type, renderer);
  });
}

export { adapters };

import React, { useState } from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import { ScreenRenderer } from '../services/sdui/renderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import {
  voucherFormAbastecimento,
  voucherFormEstacionamento,
  voucherSummaryAbastecimento,
  voucherSummaryEstacionamento,
  voucherConclusionAbastecimento,
  voucherConclusionEstacionamento,
  voucherRulesAbastecimento,
  voucherRulesEstacionamento,
} from '../services/sdui/mocks';

registerAllAdapters();

const ALL_SCREENS = {
  'Form — Abastecimento': voucherFormAbastecimento,
  'Form — Estacionamento': voucherFormEstacionamento,
  'Summary — Abastecimento': voucherSummaryAbastecimento,
  'Summary — Estacionamento': voucherSummaryEstacionamento,
  'Conclusion — Abastecimento': voucherConclusionAbastecimento,
  'Conclusion — Estacionamento': voucherConclusionEstacionamento,
  'Rules — Abastecimento': voucherRulesAbastecimento,
  'Rules — Estacionamento': voucherRulesEstacionamento,
};

type ScreenKey = keyof typeof ALL_SCREENS;
const SCREEN_KEYS = Object.keys(ALL_SCREENS) as ScreenKey[];

function MockPayloadsDemo() {
  const [selected, setSelected] = useState<ScreenKey>('Form — Abastecimento');
  const screen = ALL_SCREENS[selected];

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI Mock Payloads — SP_0002.4
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Validates 4 screens x 2 products rendered from JSON payloads.
        </Text>

        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Box mb="smaller">
          <Text type="subtitleXXL" mb="nano">
            Select screen:
          </Text>
          <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
            {SCREEN_KEYS.map(key => (
              <Text
                key={key}
                type={selected === key ? 'paragraphMDM' : 'paragraphMD'}
                color={selected === key ? 'BRAND_IDENTITY_01' : 'INTENSE_COLOR_03'}
                onPress={() => setSelected(key)}
                mb="nano"
              >
                {selected === key ? `▸ ${key}` : `  ${key}`}
              </Text>
            ))}
          </View>
        </Box>

        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text type="subtitleXXL" mb="nano">
          {selected}
        </Text>

        <Box
          pd="squishSmall"
          bgColor="LIGHT_BASE_02"
          br="sm"
          mb="smaller"
        >
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof MockPayloadsDemo> = {
  title: 'SDUI/MockPayloads',
  component: MockPayloadsDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

